const CustomBasketball = props => {

    const TOURNAMENTS = '0f5f19e9-87c6-447f-8733-2f223d9c4308';
    const ROSTERS = '5ba219c9-b296-4772-b892-1e0487b4740c';
    const GAMES = 'bc6b35ba-fcc3-40ed-98b2-ca61a3fac18c';
    const TEAMS = '0b44d6ca-2fc6-410a-8a2a-7c6012baa64f';
    const PLAYERS = '7463715a-3086-4372-9d26-aa93cea4b808';
    const NEWS = '365826b5-cf49-4ab9-b178-89a1c6919d19';
    const { transactions, lastUpdates } = props;

    const [companyData, setCompanyData] = useState(JSON.parse(localStorage.getItem('companyData')) ?? { 'name': '' });

    const [players, setPlayers] = useState(transactions?.players ?? []);
    const [rosters, setRosters] = useState(transactions?.rosters ?? []);
    const [tournaments, setTournaments] = useState(transactions?.tournaments ?? []);
    const [games, setGames] = useState(transactions?.games ?? []);
    const [teams, setTeams] = useState(transactions?.teams ?? []);
    const [news, setNews] = useState(transactions?.news ?? []);


    const dispatch = useDispatch();
    const navigate = useNavigate();

    useEffect(() => {

        getAlComponentsByModuleIdPublic(PLAYERS, companyData?.id)
            .pipe(first())
            .subscribe({
                next: data => {
                    if (data?.length > 0) {
                        setPlayers(data);
                        store.dispatch(setTransactions({ news: news, players: data, rosters: rosters, teams: teams, games: games, tournaments: tournaments }));
                        store.dispatch(setLastUpdate({ ...lastUpdates, players: now() }));
                    }
                },
            });

        getAlComponentsByModuleIdPublic(ROSTERS, companyData?.id)
            .pipe(first())
            .subscribe({
                next: data => {
                    if (data?.length > 0) {
                        setRosters(data);
                        store.dispatch(setTransactions({ news: news, players: players, rosters: data, teams: teams, games: games, tournaments: tournaments }));
                        store.dispatch(setLastUpdate({ ...lastUpdates, rosters: now() }));
                    }
                },
            });

        getAlComponentsByModuleIdPublic(TEAMS, companyData?.id)
            .pipe(first())
            .subscribe({
                next: data => {
                    if (data?.length > 0) {
                        setTeams(data);
                        store.dispatch(setTransactions({ news: news, players: players, rosters: rosters, teams: data, games: games, tournaments: tournaments }));
                        store.dispatch(setLastUpdate({ ...lastUpdates, teams: now() }));
                    }
                },
            });

        getAlComponentsByModuleIdPublic(GAMES, companyData?.id)
            .pipe(first())
            .subscribe({
                next: data => {
                    if (data?.length > 0) {
                        setGames(data);
                        store.dispatch(setTransactions({ news: news, players: players, rosters: rosters, teams: teams, games: data, tournaments: tournaments }));
                        store.dispatch(setLastUpdate({ ...lastUpdates, games: now() }));
                    }
                },
            });

        getAlComponentsByModuleIdPublic(TOURNAMENTS, companyData?.id)
            .pipe(first())
            .subscribe({
                next: data => {
                    if (data?.length > 0) {
                        setTournaments(data);
                        store.dispatch(setTransactions({ news: news, players: players, rosters: rosters, teams: teams, games: games, tournaments: data }));
                        store.dispatch(setLastUpdate({ ...lastUpdates, tournaments: now() }));
                    }
                },
            });
        getAlComponentsByModuleIdPublic(NEWS, companyData?.id)
            .pipe(first())
            .subscribe({
                next: data => {
                    if (data?.length > 0) {
                        setNews(data);
                        store.dispatch(setTransactions({ news: data, players: players, rosters: rosters, teams: teams, games: games, tournaments: tournaments }));
                        store.dispatch(setLastUpdate({ ...lastUpdates, news: now() }));
                    }
                },
            });
    }, []);

    const RenderGamesCarousell = props => {

        const [thumbsSwiper, setThumbsSwiper] = useState(null);

        return <div style={{ width: '100%', height: '70vh', position: 'relative' }}>

            <Swiper
                style={{
                    '--swiper-navigation-color': '#fff',
                    '--swiper-pagination-color': '#fff',
                }}
                slidesPerView={1}
                spaceBetween={10}
                navigation={true}
                thumbs={{ swiper: thumbsSwiper }}
                modules={[FreeMode, Navigation, Thumbs, Autoplay]}
                autoplay={{
                    delay: 10000,
                    disableOnInteraction: true,
                }}
                className="gamesSwiper1"
            >
                {games.map((game, index) => {
                    return <SwiperSlide key={index}>
                        <div style={{
                            width: '100%',
                            backgroundRepeat: 'no-repeat',
                            height: '70vh',
                            backgroundImage: `linear-gradient(to bottom,rgba(255, 255, 255, 0.3), rgba(255, 255, 255, 0.0)55%,rgba(255,255,255, 0.7), rgba(255,255,255, 1.0) ),url('${game.fields.Photo}')`,
                            backgroundColor: 'transparent',
                            backgroundSize: 'cover',
                            backgroundPosition: 'center',
                            textAlign: 'left',
                            alignContent:'center'
                        }} >
                            <p style={{fontFamily: 'var(--app-text-mobile-font)',width: '1000px', fontSize: '50px', fontWeight:'bolder',color: 'white', paddingLeft: '20%'}}>
                                {game.fields.Description}
                            </p>
                        </div>
                    </SwiperSlide>
                })}

            </Swiper>


            <Swiper
                onSwiper={setThumbsSwiper}
                spaceBetween={10}
                slidesPerView={5}
                freeMode={true}
                watchSlidesProgress={true}
                modules={[FreeMode, Navigation, Thumbs, Autoplay]}
                autoplay={{
                    delay: 10000,
                    disableOnInteraction: true,
                }}
                className="gamesSwiper2"
            >

                {games.map((game, index) => {

                    return <SwiperSlide key={index}>
                        <div key={index} style={{ display: 'flex', flexDirection: 'column', padding: '20px', backgroundColor: 'transparent' }}>
                            <progress value={0} style={{ width: '100%' }} />
                            <p className="navbar-links" style={{ width: '100%' }}>
                                {game.fields.Description}
                            </p>
                        </div>
                    </SwiperSlide>;
                })}

            </Swiper>


        </div>
    };

    const Navbar = () => {
        const [nav, setNav] = useState(false);
        const [isButtonDisabled, setIsButtonDisabled] = useState(false);

        const openNav = () => {
            setNav(!nav);
        };

        return (
            <div className="navbar-section" style={{ height: isMobile ? '100px' : '240px' }}>
                <div className="navbar-title" style={{ display: 'flex', fontSize: isMobile ? '20px' : '36px' }}>
                    {FLOWHERO(isMobile ? '26px' : '36px')}

                </div>
                {/* Desktop */}
                <ul className="navbar-items" >
                    <li>
                        <Link to="/" className="navbar-links">
                            {`TOURNAMENTS`}
                        </Link>
                    </li>

                    <li>
                        <a
                            className="navbar-links"
                            style={{ cursor: 'pointer' }}
                            onClick={() => {
                                window.scrollTo({ top: 2000, behavior: 'smooth' });
                            }}
                        >
                            {'GAMES'}
                        </a>
                    </li>
                    <li>
                        <a href="#/login" className="navbar-links">
                            {`TEAMS`}
                        </a>
                    </li>
                    <li>
                        <a href="#/register" className="navbar-links">
                            {`PLAYERS`}
                        </a>
                    </li>
                    <li>
                        <a href="#/login" className="navbar-links">
                            {`LOGIN`}
                        </a>
                    </li>
                </ul>


            </div>
        );
    }

    // console.log('news', news)
    return <div style={{ display: 'flex', flexDirection: 'column' }}>
        <Navbar />
        <RenderGamesCarousell />

        <Swiper
            spaceBetween={10}
            slidesPerView={1}
            watchSlidesProgress={true}
            modules={[FreeMode, Navigation, Autoplay]}
            autoplay={{
                delay: 10000,
                disableOnInteraction: false,
            }}
            className="adSwiper"
        >
            {news.map((news_, index) => {
                return <SwiperSlide key={index}>

                    <img src={news_.fields.Link} />

                </SwiperSlide>
            })}

        </Swiper>
        <p className={cls.gameHeader} style={{ paddingLeft: '20%' }}>
            GAMES
        </p>
        <Swiper
            spaceBetween={10}
            slidesPerView={3}
            freeMode={true}

            watchSlidesProgress={true}
            modules={[FreeMode, Navigation]}
            className="gamesSwiper3"
        >

            {games.map((game, index) => {

                const info = game.fields;

                return <SwiperSlide key={index}>

                    <div style={{
                        padding: '20px', borderRadius: '20px', textAlign: 'left', display: 'flex', flexDirection: 'column', backgroundColor: 'black', boxShadow: 'rgba(100, 100, 111, 0.2) 0px 7px 29px 0px',
                        width: '100%', height: 'inherit'
                    }}>
                        <p style={{ color: 'white' }}>
                            {info?.Period ? `${info?.Period} Qtr` : info['Game Time']}
                        </p>
                        <div style={{ display: 'flex', width: '100%' }}>
                            <div style={{ width: '80%', paddingRight: '15px' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                    <div style={{ display: 'flex', width: '100%' }}>
                                        <div style={{ width: '15%' }}>
                                            <img className={cls.scoreLogo} src={teams.find(team => team?.fields['Team ID'] === info['Team A'])?.fields['Logo']} />
                                        </div>
                                        <label style={{ width: '85%' }}>
                                            {teams.length > 0 ? teams.find(team => team?.fields['Team ID'] === info['Team A'])?.fields['Team Name'] : info['Team A']}
                                        </label>
                                    </div>
                                    <label>
                                        {info.Home}
                                    </label>
                                </div>

                                <div style={{ display: 'flex', justifyContent: 'space-between' }}>

                                    <div style={{ display: 'flex', width: '100%' }}>
                                        <div style={{ width: '15%' }}>
                                            <img className={cls.scoreLogo} src={teams.find(team => team?.fields['Team ID'] === info['Team B'])?.fields['Logo']} />
                                        </div>
                                        <label style={{ width: '85%' }}>
                                            {teams.length > 0 ? teams.find(team => team?.fields['Team ID'] === info['Team B'])?.fields['Team Name'] : info['Team B']}
                                        </label>
                                    </div>


                                    <label>
                                        {info.Away}
                                    </label>
                                </div>
                            </div>
                            <div style={{ width: '20%' }}>
                                <Button light title={'More'} />
                            </div>
                        </div>

                    </div>
                </SwiperSlide>
            })}

        </Swiper>
    </div>
}


